import React from 'react';
import { Box, Typography, Grid, Avatar } from '@mui/material';

const GoalTypes = ({ data }) => {
  const emojis = {
    "penales": "⚽",
    "cabeza": "🤯",
    "pie_derecho": "👟",
    "pie_izquierdo": "👞",
    "tiros_libres": "🎯",
    "en_juego": "🏃‍♂️"
  };

  const translateType = (type) => {
    const translations = {
      "penales": "Penales",
      "cabeza": "Cabeza",
      "pie_derecho": "Pie derecho",
      "pie_izquierdo": "Pie izquierdo",
      "tiros_libres": "Tiros libres",
      "en_juego": "En juego",
      "in_game": "En juego"
    };
    return translations[type] || type;
  };

  // Si data es null o undefined, usar un objeto vacío
  const safeData = data || {};

  return (
    <Box>
      <Typography variant="h5" gutterBottom>
        Tipos de Goles
      </Typography>
      <Grid container spacing={2} justifyContent="center">
        {Object.entries(safeData).map(([type, count]) => {
          const safeType = type === 'in_game' ? 'en_juego' : type;
          return (
            <Grid item xs={4} sm={2} key={safeType}>
              <Box sx={{ display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
                <Avatar sx={{ width: 70, height: 70, bgcolor: '#00BFFF', marginBottom: 1, fontSize: '2rem' }}>
                  {emojis[safeType] || '❓'}
                </Avatar>
                <Typography variant="body2" align="center">
                  {translateType(safeType)}
                </Typography>
                <Typography variant="h6" color="primary" align="center">{count}</Typography>
              </Box>
            </Grid>
          );
        })}
      </Grid>
    </Box>
  );
};

export default GoalTypes;
